import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";
import "../App.css";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading } = useAuth();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [image, setImage] = useState(null);

  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);

  /* =========================
      ROLE CHECK (SAFE GUARD)
  ========================= */
  const role = user?.role?.toLowerCase?.() || "";
  const isAdmin = role === "admin";
  const isOwner = true; // optional: replace with backend ownership check

  /* =========================
      FETCH POST DATA
  ========================= */
  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title);
        setBody(res.data.body);
        setPreview(res.data.image || "");
      } catch (err) {
        setError("Failed to load post.");
      } finally {
        setFetching(false);
      }
    };

    fetchPost();
  }, [id]);

  /* =========================
      IMAGE HANDLER
  ========================= */
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);

    if (file) {
      setPreview(URL.createObjectURL(file));
    }
  };

  /* =========================
      UPDATE POST
  ========================= */
  const handleUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("body", body);

      if (image) {
        formData.append("image", image);
      }

      await API.put(`/posts/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate(`/post/${id}`);
    } catch (err) {
      setError("Failed to update post.");
    } finally {
      setSaving(false);
    }
  };

  /* =========================
      LOADING STATE
  ========================= */
  if (loading || fetching) {
    return <div className="container">Loading post...</div>;
  }

  /* =========================
      ACCESS CONTROL
  ========================= */
  if (!user || (!isAdmin && !isOwner)) {
    return <div className="container">Unauthorized access.</div>;
  }

  return (
    <div className="container edit-post">
      <h2>Edit Post</h2>

      {error && <p className="error">{error}</p>}

      <form onSubmit={handleUpdate} className="post-form">

        {/* TITLE */}
        <input
          type="text"
          placeholder="Post title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          required
        />

        {/* BODY */}
        <textarea
          placeholder="Write your post..."
          value={body}
          onChange={(e) => setBody(e.target.value)}
          required
        />

        {/* IMAGE */}
        <input type="file" onChange={handleImageChange} />

        {/* PREVIEW */}
        {preview && (
          <img
            src={preview}
            alt="preview"
            className="preview-img"
          />
        )}

        {/* BUTTON */}
        <button type="submit" disabled={saving}>
          {saving ? "Updating..." : "Update Post"}
        </button>
      </form>
    </div>
  );
};

export default EditPostPage;
